jQuery(document).ready(function(){jQuery(document.body).on("click",".um_secondary_dismiss",function(){jQuery(this).parents(".um-admin-notice").find(".notice-dismiss").trigger("click")}),jQuery(document.body).on("click",".um-admin-notice.is-dismissible .notice-dismiss",function(){var n=jQuery(this).parents(".um-admin-notice");let i=n.data("key"),e=n.data("nonce");wp.ajax.send("um_dismiss_notice",{data:{key:i,_wpnonce:e},success:function(){return!0},error:function(){let n;return n=-1<window.location.href.indexOf("?")?window.location.href+"&":window.location.href+"?",window.location.href=n+"um_dismiss_notice="+i+"&_wpnonce="+e,!1}})})});